{"content": "import turtle

def generate(axiom, rules, iterations):
    result = axiom
    for _ in range(iterations):
        new_result = ""
        for char in result:
            new_result += rules.get(char, char)
        result = new_result
    return result

def draw(l_string, iterations):
    t = turtle.Turtle()
    s = turtle.Screen()
    for char in l_string:
        if char == 'F':
            t.forward(10)
        elif char == '+':
            t.right(90)
        elif char == '-':
            t.left(90)

    canvas = s.getcanvas()
    canvas.postscript(file="koch_curve.ps")

if __name__ == "__main__":
    axiom = "F"
    rules = {"F": "F+F-F-F+F"}
    iterations = 3
    string = generate(axiom, rules, iterations)
    draw(string, iterations)", "path": "src/l_system_generator.py"}

